import{_ as o}from"./chunks/list.c-Tu_IS0.js";import{_ as e,H as i,f as r,i as n}from"./chunks/framework.Cvt1eIE0.js";const s="/quote/images/quote/assign_member.png",a="/quote/images/quote/set_discount.png",l="/quote/images/quote/set_shipping.png",g="/quote/images/quote/item.png",p="/quote/images/quote/discount.png",u="/quote/images/quote/shipping1.png",c="/quote/images/quote/shipping2.png",m="/quote/images/quote/timeline.png",d="/quote/images/quote/create_quote.png",h="/quote/images/quote/create_quote1.png",E=JSON.parse('{"title":"报价单后台管理","description":"","frontmatter":{},"headers":[],"relativePath":"quote/quote-management.md","filePath":"quote/quote-management.md"}'),_={name:"quote/quote-management.md"};function q(f,t,b,x,P,S){return i(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="报价单后台管理" tabindex="-1">报价单后台管理 <a class="header-anchor" href="#报价单后台管理" aria-label="Permalink to &quot;报价单后台管理&quot;">​</a></h1><p>在本章节中，您将学习如何高效地处理来自客户的报价申请，以及如何手动为客户创建报价单。</p><h2 id="_1-报价单列表与详情" tabindex="-1">1. 报价单列表与详情 <a class="header-anchor" href="#_1-报价单列表与详情" aria-label="Permalink to &quot;1. 报价单列表与详情&quot;">​</a></h2><p>登录应用后台，点击 <strong>报价单 (Quotes)</strong> 菜单。</p><h3 id="列表页可以做什么" tabindex="-1">列表页可以做什么 <a class="header-anchor" href="#列表页可以做什么" aria-label="Permalink to &quot;列表页可以做什么&quot;">​</a></h3><p>进入 <strong>Quote Management</strong> 后，您会先看到报价单列表页面。这里是日常处理报价的主工作区，大部分操作都会先从这里开始。</p><p><img src="'+o+'" alt="报价单列表"></p><p>列表页会显示每一笔报价的关键信息，包括：</p><ul><li><strong>Quote ID</strong>：报价单编号，便于内部沟通和排查。</li><li><strong>Draft order</strong>：对应的 Shopify 草稿订单编号；如果还没有生成，会显示为空。</li><li><strong>Quote name</strong>：报价名称。</li><li><strong>Customer name / Email</strong>：客户名称与邮箱。</li><li><strong>Expected total</strong>：客户提交时预期的金额。</li><li><strong>Total</strong>：当前报价单中实际配置的金额。</li><li><strong>Date</strong>：报价提交时间。</li><li><strong>Expires</strong>：报价过期时间；如果尚未发送 invoice，通常会显示为空。</li><li><strong>Status</strong>：当前报价状态。</li><li><strong>Assigned to</strong>：当前分配给哪位成员跟进。</li></ul><h3 id="列表页常用操作" tabindex="-1">列表页常用操作 <a class="header-anchor" href="#列表页常用操作" aria-label="Permalink to &quot;列表页常用操作&quot;">​</a></h3><p>在列表页，您可以直接完成以下操作：</p><ul><li><strong>搜索报价单</strong>：可按报价单编号、客户名称、邮箱或关键词搜索。</li><li><strong>按状态筛选</strong>：例如只看 <code>Pending</code>、<code>Sent</code>、<code>Accepted</code>、<code>Expired</code> 等状态。</li><li><strong>按日期筛选</strong>：通过开始时间和结束时间缩小查询范围。</li><li><strong>导出 Excel</strong>：导出当前筛选结果，方便交接、归档或二次分析。</li><li><strong>打开详情页</strong>：点击每一行右侧的 <strong>Open</strong>，进入该报价单详情。</li><li><strong>删除报价单</strong>：如确认该记录无效，可在列表页直接删除。</li></ul><h3 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h3><p>如果您需要同时处理多笔报价，可以先勾选列表左侧复选框，再执行批量操作。根据当前账号权限，列表页可能支持：</p><ul><li><strong>Assign Member</strong>：批量分配负责人。</li></ul><p><img src="'+s+'" alt="批量分配成员"></p><ul><li><strong>Set Discount</strong>：批量设置折扣。</li></ul><p><img src="'+a+'" alt="批量设置优惠"></p><ul><li><strong>Set Shipping</strong>：批量设置运费。</li></ul><p><img src="'+l+'" alt="批量设置运费"></p><ul><li><strong>Delete Selected</strong>：批量删除已选报价单。</li></ul><p>如果您没有看到这些按钮，通常表示当前成员账号没有对应权限。</p><h3 id="状态说明" tabindex="-1">状态说明 <a class="header-anchor" href="#状态说明" aria-label="Permalink to &quot;状态说明&quot;">​</a></h3><ul><li><strong>待处理 (Pending)</strong>: 客户刚提交申请，等待商家审核。</li><li><strong>已审阅 (Reviewd)</strong>: 商家更新了报价单。</li><li><strong>已发送 (Sent)</strong>: 商家已修改价格并向客户发送了报价方案。</li><li><strong>已批准 (Approved)</strong>: 客户已接受报价。</li><li><strong>已拒绝 (Rejected)</strong>: 报价未达成一致。</li><li><strong>已过期 (Expired)</strong>: 超过了设定的有效期。</li></ul><h3 id="详情页操作" tabindex="-1">详情页操作 <a class="header-anchor" href="#详情页操作" aria-label="Permalink to &quot;详情页操作&quot;">​</a></h3><p>在报价单详情页，您可以：</p><ul><li><strong>修改价格</strong>: 针对每一个产品行修改单价或数量</li></ul><p><img src="'+g+'" alt="配置quote价格"></p><ul><li><strong>添加优惠</strong>: 针对整个报价单添加优惠。</li></ul><p><img src="'+p+'" alt="配置discount"></p><ul><li><strong>添加运费</strong>: 针对整个报价单添加运费，运费可以自定义也可使用默认的</li></ul><p><img src="'+u+'" alt="配置shipping"></p><p><img src="'+c+'" alt="配置shipping"></p><ul><li><strong>留言并且可查看操作记录</strong>: 追踪该报价单从创建到成交的所有操作记录。 <img src="'+m+'" alt="timeline"></li></ul><h2 id="_2-处理流程-从申请到订单" tabindex="-1">2. 处理流程：从申请到订单 <a class="header-anchor" href="#_2-处理流程-从申请到订单" aria-label="Permalink to &quot;2. 处理流程：从申请到订单&quot;">​</a></h2><ol><li><strong>审核与调整</strong>: 收到申请后，您可以根据实际情况调整价格、数量、运费或优惠。</li><li><strong>同意报价</strong>: 点击“send invoice”，系统会通过邮件通知客户,并且一键将报价单转换为 Shopify 的 <strong>草稿订单 (Draft Order)</strong> 并发送正式发票。</li><li><strong>结账</strong>: 客户支付发票后，该报价单将自动标记为已完成。</li></ol><h2 id="_3-手动创建报价单" tabindex="-1">3. 手动创建报价单 <a class="header-anchor" href="#_3-手动创建报价单" aria-label="Permalink to &quot;3. 手动创建报价单&quot;">​</a></h2><p>如果您在电话或线下与客户达成了初步意向，也可以点击 <strong>“新建报价单”</strong>：</p><ul><li>搜索并选择现有的客户。</li><li>搜索并添加产品。</li><li>设置报价单的有效期。</li></ul><p><img src="'+d+'" alt="创建报价单"></p><h2 id="" tabindex="-1"><img src="'+h+'" alt=""> <a class="header-anchor" href="#" aria-label="Permalink to &quot;![](/quote/images/quote/create_quote1.png)&quot;">​</a></h2><h2 id="技巧" tabindex="-1">技巧 <a class="header-anchor" href="#技巧" aria-label="Permalink to &quot;技巧&quot;">​</a></h2><p>善用 <strong>“状态进度条”</strong>，可以直观地查看当前报价单处于哪个阶段。</p>',43)])])}const A=e(_,[["render",q]]);export{E as __pageData,A as default};
